import{_ as i,o as t,c as a,ag as r}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"📘 COURS : LE DIABÈTE","description":"","frontmatter":{},"headers":[],"relativePath":"matieres/sante/cours/diabete-endo.md","filePath":"matieres/sante/cours/diabete-endo.md"}'),n={name:"matieres/sante/cours/diabete-endo.md"};function s(l,e,o,u,d,c){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="📘-cours-le-diabete" tabindex="-1">📘 COURS : LE DIABÈTE <a class="header-anchor" href="#📘-cours-le-diabete" aria-label="Permalink to &quot;📘 COURS : LE DIABÈTE&quot;">​</a></h1><h2 id="_1️⃣-definition-du-diabete" tabindex="-1">1️⃣ Définition du diabète <a class="header-anchor" href="#_1️⃣-definition-du-diabete" aria-label="Permalink to &quot;1️⃣ Définition du diabète&quot;">​</a></h2><p>Le diabète est une <strong>maladie chronique</strong> caractérisée par une <strong>hyperglycémie persistante</strong> (taux de glucose élevé dans le sang), due à :</p><ul><li>un <strong>défaut de sécrétion d’insuline</strong></li><li>et/ou une <strong>résistance à l’insuline</strong></li></ul><p>👉 <strong>L’insuline</strong> est une hormone produite par le <strong>pancréas</strong> qui permet au <strong>glucose d’entrer dans les cellules</strong>.</p><hr><h2 id="_2️⃣-types-de-diabete" tabindex="-1">2️⃣ Types de diabète <a class="header-anchor" href="#_2️⃣-types-de-diabete" aria-label="Permalink to &quot;2️⃣ Types de diabète&quot;">​</a></h2><h3 id="🔹-diabete-de-type-1" tabindex="-1">🔹 Diabète de type 1 <a class="header-anchor" href="#🔹-diabete-de-type-1" aria-label="Permalink to &quot;🔹 Diabète de type 1&quot;">​</a></h3><ul><li>Destruction <strong>auto-immune des cellules β du pancréas</strong></li><li><strong>Absence totale d’insuline</strong></li><li>Survient surtout chez <strong>l’enfant et l’adulte jeune</strong></li></ul><p><strong>Traitement :</strong></p><ul><li>Insuline <strong>à vie</strong></li></ul><p><strong>Signes fréquents :</strong></p><ul><li>Polyurie</li><li>Polydipsie</li><li>Amaigrissement</li><li>Fatigue</li></ul><hr><h3 id="🔹-diabete-de-type-2" tabindex="-1">🔹 Diabète de type 2 <a class="header-anchor" href="#🔹-diabete-de-type-2" aria-label="Permalink to &quot;🔹 Diabète de type 2&quot;">​</a></h3><ul><li><strong>Insulinorésistance</strong> + <strong>déficit progressif en insuline</strong></li><li>Le <strong>plus fréquent</strong></li></ul><p><strong>Facteurs de risque :</strong></p><ul><li>Surpoids / obésité</li><li>Sédentarité</li><li>Antécédents familiaux</li><li>Âge</li></ul><p><strong>Traitement :</strong></p><ul><li>Mesures <strong>hygiéno-diététiques</strong></li><li><strong>Antidiabétiques oraux</strong></li><li><strong>Insuline si nécessaire</strong></li></ul><hr><h3 id="🔹-autres-types" tabindex="-1">🔹 Autres types <a class="header-anchor" href="#🔹-autres-types" aria-label="Permalink to &quot;🔹 Autres types&quot;">​</a></h3><ul><li>Diabète <strong>gestationnel</strong></li><li>Diabètes <strong>secondaires</strong> (médicaments, maladies endocriniennes…)</li></ul><hr><h2 id="_3️⃣-diagnostic-biologique" tabindex="-1">3️⃣ Diagnostic biologique <a class="header-anchor" href="#_3️⃣-diagnostic-biologique" aria-label="Permalink to &quot;3️⃣ Diagnostic biologique&quot;">​</a></h2><p>👉 Le diagnostic repose sur la <strong>glycémie</strong> :</p><ul><li><strong>Glycémie à jeun ≥ 1,26 g/L (7,0 mmol/L)</strong> à deux reprises</li><li><strong>OU glycémie ≥ 2 g/L avec symptômes</strong></li><li><strong>HbA1c ≥ 6,5 %</strong></li></ul><p>📌 <strong>HbA1c</strong> : reflète la <strong>moyenne de la glycémie sur 2–3 mois</strong>.</p><hr><h2 id="_4️⃣-complications-du-diabete" tabindex="-1">4️⃣ Complications du diabète <a class="header-anchor" href="#_4️⃣-complications-du-diabete" aria-label="Permalink to &quot;4️⃣ Complications du diabète&quot;">​</a></h2><h3 id="🔴-complications-aigues" tabindex="-1">🔴 Complications aiguës <a class="header-anchor" href="#🔴-complications-aigues" aria-label="Permalink to &quot;🔴 Complications aiguës&quot;">​</a></h3><ul><li>Hypoglycémie</li><li>Acidocétose diabétique (surtout type 1)</li><li>Hyperglycémie hyperosmolaire</li></ul><h3 id="🔴-complications-chroniques" tabindex="-1">🔴 Complications chroniques <a class="header-anchor" href="#🔴-complications-chroniques" aria-label="Permalink to &quot;🔴 Complications chroniques&quot;">​</a></h3><h4 id="microvasculaires" tabindex="-1">Microvasculaires <a class="header-anchor" href="#microvasculaires" aria-label="Permalink to &quot;Microvasculaires&quot;">​</a></h4><ul><li>Rétinopathie</li><li>Néphropathie</li><li>Neuropathie</li></ul><h4 id="macrovasculaires" tabindex="-1">Macrovasculaires <a class="header-anchor" href="#macrovasculaires" aria-label="Permalink to &quot;Macrovasculaires&quot;">​</a></h4><ul><li>AVC</li><li>Infarctus</li><li>Artériopathie des membres inférieurs</li></ul><hr><h2 id="_5️⃣-traitement-du-diabete" tabindex="-1">5️⃣ Traitement du diabète <a class="header-anchor" href="#_5️⃣-traitement-du-diabete" aria-label="Permalink to &quot;5️⃣ Traitement du diabète&quot;">​</a></h2><h3 id="🥗-mesures-non-medicamenteuses" tabindex="-1">🥗 Mesures non médicamenteuses <a class="header-anchor" href="#🥗-mesures-non-medicamenteuses" aria-label="Permalink to &quot;🥗 Mesures non médicamenteuses&quot;">​</a></h3><ul><li>Alimentation <strong>équilibrée</strong></li><li><strong>Activité physique régulière</strong></li><li><strong>Perte de poids</strong> si nécessaire</li><li><strong>Éducation thérapeutique</strong></li></ul><h3 id="💊-traitement-medicamenteux" tabindex="-1">💊 Traitement médicamenteux <a class="header-anchor" href="#💊-traitement-medicamenteux" aria-label="Permalink to &quot;💊 Traitement médicamenteux&quot;">​</a></h3><ul><li><strong>Metformine</strong> (1ère intention type 2)</li><li><strong>Sulfamides hypoglycémiants</strong></li><li><strong>Inhibiteurs DPP-4, GLP-1, SGLT2</strong></li><li><strong>Insuline</strong></li></ul><hr><h2 id="_6️⃣-surveillance-du-patient-diabetique" tabindex="-1">6️⃣ Surveillance du patient diabétique <a class="header-anchor" href="#_6️⃣-surveillance-du-patient-diabetique" aria-label="Permalink to &quot;6️⃣ Surveillance du patient diabétique&quot;">​</a></h2><ul><li><strong>Glycémie capillaire</strong></li><li><strong>HbA1c tous les 3–6 mois</strong></li></ul><p>Surveillance de :</p><ul><li>Pieds</li><li>Tension artérielle</li><li>Poids</li><li>Fonction rénale</li><li>Vision</li></ul><hr><h2 id="_7️⃣-role-infirmier-tres-important-👨‍⚕️👩‍⚕️" tabindex="-1">7️⃣ Rôle infirmier (très important 👨‍⚕️👩‍⚕️) <a class="header-anchor" href="#_7️⃣-role-infirmier-tres-important-👨‍⚕️👩‍⚕️" aria-label="Permalink to &quot;7️⃣ Rôle infirmier (très important 👨‍⚕️👩‍⚕️)&quot;">​</a></h2><ul><li><strong>Éducation du patient</strong></li><li>Apprentissage de <strong>l’auto-surveillance</strong></li><li>Reconnaissance des <strong>signes d’hypoglycémie / hyperglycémie</strong></li><li><strong>Administration et surveillance de l’insuline</strong></li><li><strong>Prévention des complications</strong></li><li><strong>Soutien psychologique</strong></li></ul>',51)])])}const h=i(n,[["render",s]]);export{m as __pageData,h as default};
